import{_ as r,o as t,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"53. Recall Return To Workplace","description":"","frontmatter":{"title":"53. Recall Return To Workplace","eba":"Allied Health Professionals 2021-2026","topics":["hours","overtime","rosters","on-call"]},"headers":[],"relativePath":"ebas/allied-health/hours-of-work/53-recall-return-to-workplace.md","filePath":"ebas/allied-health/hours-of-work/53-recall-return-to-workplace.md"}'),l={name:"ebas/allied-health/hours-of-work/53-recall-return-to-workplace.md"};function n(c,e,s,i,p,h){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_53-recall-return-to-workplace" tabindex="-1">53. Recall Return To Workplace <a class="header-anchor" href="#_53-recall-return-to-workplace" aria-label="Permalink to &quot;53. Recall Return To Workplace&quot;">​</a></h1><p><strong>53.1</strong> The relevant rate for recall is at subclause 52.6 (Payment of Authorised Overtime and Recall to Duty) above.</p><p><strong>53.2</strong> An Employee who is recalled to duty, (whether on-call or not) where the work is not continuous with the Employee&#39;s next succeeding rostered period of ordinary duty will be paid:</p><p><strong>(a)</strong> from the time of receiving the recall until the time of returning to the place from which the Employee was recalled; and</p><p><strong>(b)</strong> a minimum of three (3) hours’ pay at the applicable overtime rates for each recall.</p>',5)])])}const m=r(l,[["render",n]]);export{d as __pageData,m as default};
